132	[Cotangent exact sequence for a composition]
133	  \label{thm:cotangent_exact_sequence}
134	  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
135	  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
136	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
137	  \[
138	    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
139	      \Omega_{X/Y} \;\longrightarrow\; 0,
140	  \]
141	  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
142	\end{theorem}
